using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(b =>
        {
            // #1 Discriminator property renamed from "Discriminator" to "$type" in EF9.
            //    Preserve old name so existing documents and raw SQL
            //    (e.g. "WHERE c.Discriminator = 'Blog'") keep working.
            b.HasDiscriminator<string>("Discriminator");

            // #2 JSON id no longer includes the discriminator prefix in EF9.
            //    Existing docs have id = "Blog|1"; re-enable the old format.
            b.HasDiscriminatorInJsonId();

            // #3 Key property now maps directly to JSON "id" in EF9.
            //    Existing docs also store it under a separate "Id" JSON property.
            //    Re-enable the old shadow __id property so both stay consistent.
            b.HasShadowId();

            // #4 HasIndex throws on Cosmos in EF9 — removed.
            //    (was: b.HasIndex(b => b.Name);)
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

